struct cpu cpus[NCPU];

struct proc proc[NPROC];

extern thread *free_thread;

struct proc *initproc;

int nextpid = 1;
struct spinlock pid_lock;

extern void forkret(void);
static void freeproc(struct proc *p);

extern char trampoline[]; // trampoline.S
extern char signalTrampoline[]; // signalTrampoline.S

struct spinlock wait_lock;

void proc_mapstacks(pagetable_t kpgtbl) {
  struct proc *p;

  for(p = proc; p < &proc[NPROC]; p++) {
    char *pa = kalloc();
    if(pa == 0)
      panic("kalloc");
    uint64_t va = KSTACK((int) (p - proc));
    kvmmap(kpgtbl, va, (uint64_t)pa, PGSIZE, PTE_R | PTE_W);
  }
}

// initialize the proc table.
void procinit(void) {
  struct proc *p;

  initlock(&pid_lock, "nextpid");
  initlock(&wait_lock, "wait_lock");
  for(p = proc; p < &proc[NPROC]; p++) {
      initlock(&p->lock, "proc");
      p->state = UNUSED;
      p->kstack = KSTACK((int) (p - proc));
  }
}

// Must be called with interrupts disabled,
// to prevent race with process being moved
// to a different CPU.
int cpuid()
{
  int id = r_tp();
  return id;
}

struct cpu* mycpu(void)
{
  int id = cpuid();
  struct cpu *c = &cpus[id];
  return c;
}

struct proc* myproc(void)
{
  push_off();
  struct cpu *c = mycpu();
  struct proc *p = c->proc;
  pop_off();
  return p;
}

int allocpid()
{
  int pid;

  acquire(&pid_lock);
  pid = nextpid;
  nextpid = nextpid + 1;
  release(&pid_lock);

  return pid;
}

static void copy_context(struct context *t1, struct context *t2){
  t1->ra = t2->ra;
  t1->sp = t2->sp;
  t1->s0 = t2->s0;
  t1->s1 = t2->s1;
  t1->s2 = t2->s2;
  t1->s3 = t2->s3;
  t1->s4 = t2->s4;
  t1->s5 = t2->s5;
  t1->s6 = t2->s6;
  t1->s7 = t2->s7;
  t1->s8 = t2->s8;
  t1->s9 = t2->s9;
  t1->s10 = t2->s10;
  t1->s11 = t2->s11;
}

