// Look in the process table for an UNUSED proc.
// If found, initialize state required to run in the kernel,
// and return with p->lock held.
// If there are no free procs, or a memory allocation fails, return 0.
static struct proc* allocproc(void)
{
  struct proc *p;

  for(p = proc; p < &proc[NPROC]; p++) {
    acquire(&p->lock);
    if(p->state == UNUSED) {
      goto found;
    } else {
      release(&p->lock);
    }
  }
  return 0;

found:
  p->pid = allocpid();
  p->uid = 0;
  p->gid = 0;
  p->pgid = 0;
  p->state = USED;

  // Allocate a trapframe page.
  if((p->trapframe = (struct trapframe *)kalloc()) == 0){
    freeproc(p);
    release(&p->lock);
    return 0;
  }

  // An empty user page table.
  if ((p->pagetable = proc_pagetable(p)) == NULL /*||
      (p->kpagetable = proc_pagetable(p)) == NULL */) {
      freeproc(p);
      release(&p->lock);
      return NULL;
  }

  memset(&p->context, 0, sizeof(p->context));
  p->context.ra = (uint64_t)forkret;
  p->context.sp = p->kstack + PGSIZE;
  /*
  p->main_thread = allocNewThread();
  copy_context(&p->main_thread->context, &p->context);
  p->thread_num++;
  p->main_thread->p = p;
  p->main_thread->sz = p->sz;
  p->main_thread->clear_child_tid = p->clear_child_tid;
  p->main_thread->kstack = p->kstack;
  p->thread_queue = p->main_thread;
  */

  return p;
}

// free a proc structure and the data hanging from it,
// including user pages.
// p->lock must be held.
static void freeproc(struct proc *p)
{
  //printf("free proc %d\n", myproc()->pid);
  if(p->trapframe)
    kfree((void*)p->trapframe);
  p->trapframe = 0;
  if (p->kpagetable) {
    kfree(p->kpagetable);
  }
  p->kpagetable = 0;
  //printf("freeproc: %p\n", p->sz);
  if(p->pagetable)
    proc_freepagetable(p->pagetable, p->sz);
  p->pagetable = 0;
  p->sz = 0;
  p->pid = 0;
  p->parent = 0;
  p->name[0] = 0;
  p->chan = 0;
  p->killed = 0;
  p->xstate = 0;
  p->state = UNUSED;
}

pagetable_t proc_pagetable(struct proc *p)
{
  pagetable_t pagetable;

  // An empty page table.
  pagetable = uvmcreate();
  if(pagetable == 0)
    return 0;

  if(mappages(pagetable, TRAMPOLINE, PGSIZE,
              (uint64_t)trampoline, PTE_R | PTE_X) < 0){
    uvmfree(pagetable, 0);
    return 0;
  }
  if(mappages(pagetable, TRAPFRAME, PGSIZE,
              (uint64_t)(p->trapframe), PTE_R | PTE_W) < 0){
    uvmunmap(pagetable, TRAMPOLINE, 1, 0);
    uvmfree(pagetable, 0);
    return 0;
  }
  if (mappages(pagetable, SIGTRAMPOLINE, PGSIZE, (uint64_t)signalTrampoline,
               PTE_R | PTE_X | PTE_U) < 0) {
    uvmunmap(pagetable, TRAMPOLINE, 1, 0);
    uvmunmap(pagetable, TRAPFRAME, 1, 0);
    uvmfree(pagetable, 0);
    return 0;
  }
  return pagetable;
}

void proc_freepagetable(pagetable_t pagetable, uint64_t sz){
  //printf("proc_freepagetable\n");
  uvmunmap(pagetable, TRAMPOLINE, 1, 0);
  uvmunmap(pagetable, TRAPFRAME, 1, 0);
  uvmfree(pagetable, sz);
  //printf("Debug\n");
}


