/*
页表，虚实地址转换
*/
#include "param.h"
#include "platform.h"
#include "types.h"
#include "os.h"
#include "riscv.h"
#include "spinlock.h"
#include "proc.h"
#include "memlayout.h"
#include "defs.h"

pagetable_t kernel_pagetable;

extern char etext[];

extern char trampoline[];

void kvmmap(pagetable_t kpgtbl, uint64_t va, uint64_t pa, uint64_t sz, int perm);
pa_t walkaddr(pagetable_t pagetable, uint64_t va);

pagetable_t kvmmake(void){
    pagetable_t kpgtbl;

    kpgtbl = (pagetable_t) kalloc();
    memset(kpgtbl, 0, PGSIZE);

    kvmmap(kpgtbl, Uart0, Uart0, PGSIZE, PTE_R | PTE_W);
    //printf("串口地址映射完成\n");

    kvmmap(kpgtbl, VIRTIO0, VIRTIO0, PGSIZE, PTE_R | PTE_W);
    //printf("VIRTIO0地址映射完成\n");

    //printf("kerbase vm->pa : %0x\n", walkaddr(kpgtbl,PLIC, 0));
    kvmmap(kpgtbl, PLIC, PLIC, 0x400000, PTE_R | PTE_W);
    //printf("PLIC地址映射完成\n");

    //printf("kerbase vm->pa : %0x\n", walkaddr(kpgtbl,KERNBASE, 0));
    kvmmap(kpgtbl, KERNBASE, KERNBASE, (uint64_t)etext-KERNBASE, PTE_R | PTE_X);
    //printf("KERNBASE地址映射完成\n");

    kvmmap(kpgtbl, (uint64_t)etext, (uint64_t)etext, PHYSTOP-(uint64_t)etext, PTE_R | PTE_W);
    //printf("etext地址映射完成\n");

    kvmmap(kpgtbl, TRAMPOLINE, (uint64_t)trampoline, PGSIZE, PTE_R | PTE_X);
    //printf("TRAMPOLINE地址映射完成\n");

    proc_mapstacks(kpgtbl);

    return kpgtbl;
}

void kvminit(void) {
    //printf("kvminit start\n");
    kernel_pagetable = kvmmake();
    //printf("kvminit end\n");
}

void kvminithart(){
    //printf("kvminithart start\n");
    //sfence_vma();

    asm volatile("csrw satp, %0" : : "r" (MAKE_SATP(kernel_pagetable)));
    //w_satp(MAKE_SATP(kernel_pagetable)); // satp寄存器模式设为8，开启分页
    //printf("kvminithart me\n");
    asm volatile("sfence.vma zero, zero");
    //sfence_vma();
    //printf("kvminithart end\n");
}

pte_t * walk(pagetable_t pagetable, uint64_t va, int alloc){
    if(va >= MAXVA){
        printf("%p\n", va);
      panic("walk");
    }

    for(int vm_l = 2; vm_l > 0; vm_l --){
        pte_t *pte = &pagetable[PX(vm_l, va)];
        if(*pte & PTE_V){
            pagetable = (pagetable_t) PTE2PA(* pte);
        }else{
            if(!alloc || (pagetable = ((pde_t *) kalloc())) == 0){
                return 0;
            }
            memset(pagetable, 0, PGSIZE);
            *pte = PA2PTE(pagetable) | PTE_V;
        }
    }
    return &pagetable[PX(0, va)];
}

pa_t walkaddr(pagetable_t pagetable, uint64_t va){
    pte_t *pte;
    pa_t pa;

    if(va >= MAXVA){
      return 0;
    }

    pte = walk(pagetable, va, 0);

    if(!pte || !(*pte & PTE_V) || !(*pte & PTE_U)){
      //printf("woc: %p %p %p %p %p %p\n", va, pte, *pte, *pte & PTE_V, *pte & PTE_U, PTE2PA(*pte));
      return 0;
    }
    pa = PTE2PA(*pte);
    return pa;
}

void kvmmap(pagetable_t kpgtbl, uint64_t va, uint64_t pa, uint64_t sz, int perm)
{
    if(mappages(kpgtbl, va, sz, pa, perm) != 0)
        panic("kvmmap");
}

int mappages(pagetable_t pagetable, uint64_t va, uint64_t size, uint64_t pa, int perm)
{
    uint64_t a, last;

    pte_t *pte;

    if(size == 0)
        panic("mappages: size");

    a = PGROUNDDOWN(va);
    last = PGROUNDDOWN(va + size - 1);
    for(;;){
        if((pte = walk(pagetable, a, 1)) == 0)
            panic("walk return -1\n");
        if(*pte & PTE_V) {
            printf("mappages: %p\n", va);
            panic("mappages: remap");
        }
        *pte = PA2PTE(pa) | perm | PTE_V;
        *pte = PA2PTE(pa) | perm | PTE_V;
        *pte = PA2PTE(pa) | perm | PTE_V;
        //printf("mappages: %p %p %p %p %p %p %p\n", perm, perm & PTE_R,  perm & PTE_W, perm & PTE_X,  perm & PTE_U, *pte, pte);
        //printf("mappages: %p %p\n", a, pa);
        if(a == last)
            break;
        //if(a < 0x80000000)
            //printf("mappages: va: %p pa: %p\n", a, pa);
        a += PGSIZE;
        //printf("mappages: %p\n", pa);
        pa += PGSIZE;
    }
    return 0;
}

#define PTE_FLAGS(pte) ((pte) & 0x3FF)
void uvmunmap(pagetable_t pagetable, uint64_t va, uint64_t npages, int do_free){
    uint64_t a;
    pte_t *pte;
    if((va % PGSIZE) != 0){
        panic("uvmunmap : not aligned");
    }
    //printf("uvmunmap: %p\n", va);
    for(a = va; a < va + npages * PGSIZE; a += PGSIZE){
        if ((pte = walk(pagetable, a, 0)) == 0)
            panic("vmunmap: walk");
        if ((*pte & PTE_V) == 0) {
            //printf("uvmunmap: %p\n", a);
            panic("vmunmap: not mapped");
        }

        if (PTE_FLAGS(*pte) == PTE_V)
            panic("vmunmap: not a leaf");
        if(do_free){
            uint64_t pa = PTE2PA(*pte);
            kfree((void*)pa);
        }
        *pte = 0;
    }
} 

pagetable_t uvmcreate(){
    pagetable_t pagetable;

    if((pagetable = (pagetable_t) kalloc()) == 0){
        return 0;
    }
    memset(pagetable, 0, PGSIZE);
    return pagetable;
}

void uvmfirst(pagetable_t pagetable, uint8_t *src, uint32_t sz){
  char *mem;
  uint64_t i;
  for( i= 0; i + PGSIZE < sz; i += PGSIZE){
    mem = kalloc();
    memset(mem, 0, PGSIZE);
    mappages(pagetable, i, PGSIZE, (uint64_t)mem, PTE_W | PTE_R | PTE_X | PTE_U);
    memmove(mem, src + i, PGSIZE);
  }
  mem = kalloc();
  memset(mem, 0, PGSIZE);
  mappages(pagetable, i, PGSIZE, (uint64_t)mem, PTE_W|PTE_R|PTE_X|PTE_U);
  memmove(mem, src + i, sz % PGSIZE);
  //printf("uvmfirst\n");
}

uint64_t uvmalloc(pagetable_t pagetable, uint64_t oldsz, uint64_t newsz, int xperm){
    char *mem;
    uint64_t a;
    if(newsz < oldsz){
        return oldsz;
    }
    oldsz = PGROUNDUP(oldsz);
    //printf("uvmalloc : %p   %p\n", oldsz, newsz);
    for(a = oldsz; a < newsz; a += PGSIZE){
        mem = kalloc();
        if(mem == 0){
            printf("mem==0\n");
            uvmdealloc(pagetable, a, oldsz);
            return 0;
        }
        memset(mem, 0, PGSIZE);
        //printf("vmalloc: %p\n", a);
        if(mappages(pagetable, a, PGSIZE, (uint64_t)mem, PTE_R | PTE_U | xperm)){
            printf("woc1!!!!!!!!!!!!!!!!!!\n");
            kfree(mem);
            uvmdealloc(pagetable , a, oldsz);
            return 0;
        }
    }
    //printf("uvmalloc: newsize: %p\n", newsz);
    return newsz;
}

uint64_t uvmdealloc(pagetable_t pagetable, uint64_t oldsz, uint64_t newsz){
    if(newsz > oldsz){
        return oldsz;
    }
    printf("uvmdealloc\n");
    if(PGROUNDUP(oldsz) > PGROUNDUP(newsz)){
        int npages = (PGROUNDUP(oldsz) - PGROUNDUP(newsz)) / PGSIZE;
        uvmunmap(pagetable, PGROUNDUP(newsz), npages, 1);
    }

    return newsz;
}

void freewalk(pagetable_t pagetable)
{
    // 有512页表项
    if(!pagetable){
        return;
    }
    //printf("free walk : %p\n", pagetable);
    //printf("free\n");
    for(int i = 0; i < 512; i++){
        pte_t pte = pagetable[i];
        if((pte & PTE_V) && (pte & (PTE_R|PTE_W|PTE_X)) == 0){
            // 中间页表项
            uint64_t child = PTE2PA(pte);
            freewalk((pagetable_t)child);
            pagetable[i] = 0;
        } else if(pte & PTE_V){
            continue;
