extern char end[];

struct run{
    struct run *next;
};

struct {
    struct spinlock lock;
    struct run *freelist;
    uint64_t npage;
} kmem;

void kfree(void *pa){
    struct run *r;
    if(((uint64_t)pa % PGSIZE) != 0){
        panic("kfree: pa not aliend");
    }
    if((char *)pa < end) {
        panic("kfree: pa less than end");
    }
    if((uint64_t)pa >= PHYSTOP) {

        panic("kfree: pa bigger than phymax");
    }
    memset(pa, 1, PGSIZE);
    //printf("kfree: %p\n", pa);
    r = (struct run*)pa;

    acquire(&kmem.lock);
    r->next = kmem.freelist;
    kmem.freelist = r;
    kmem.npage++;
    release(&kmem.lock);
}

void kinit(){
    //printf("kinit\n");
    initlock(&kmem.lock, "kmem");
    freerange(end, (void *)PHYSTOP);
    //printf("kinit\n");
}

void freerange(void *pa_start, void *pa_end){
    char *p;
    p = (char *)PGROUNDUP((uint64_t) pa_start);
    for(; p + PGSIZE <= (char *)pa_end; p+= PGSIZE){
        kfree(p);
    }
}

void * kalloc(void) {
    struct run *r;

    acquire(&kmem.lock);
    r = kmem.freelist;
    if(r) {
        //printf("kalloc:%p %p %p %p\n", r, r->next, r->next->next, r->next->next->next);
        kmem.freelist = r->next;
        kmem.npage--;
    }
    release(&kmem.lock);

    if(r)
        memset((char*)r, 5, PGSIZE);
    return (void*)r;
}

uint64_t freemem_amount(void)
{
  return kmem.npage << PGSHIFT;
}

