uint64_t balloc(uint32_t dev)
{
    int inum;
    struct buf *bp;
    struct ext4_inode *dip;
    struct dirent dirent;
    uint64_t block_map_address = (uint64_t)(ext4_bgroup[0].block_bitmap_hi << 32 )+ (uint64_t)ext4_bgroup[0].block_bitmap_lo;
    //printf("inode address: %d\n", inode_map_address);
    for(inum = 0; inum < 4096; inum+=1024){
      bp = bread(dev, (block_map_address) << 2 + inum / BSIZE);

      for(int i = 0; i < 1024; i++){
        int mask = 0x80;
        int pos = 0;
        while(mask){
          if(!(bp->data[i] & mask) && i * 8 + pos + inum * 8 > 11){
            //printf("inum: %d %d\n", i * 8 + pos + inum * 8, bp->data[0]);
