            virtio_disk_rw(bp, 1);
            brelse(bp);
            return (uint64_t)i * 8 + pos + inum * 8;
          }
          pos++;
          mask >>= 1;
        }
      }

      brelse(bp);
    }
    printf("ialloc: no inodes\n");
    return 0;
}

