void mount_init(void){
    struct mnt *rootmnt = &(global_mnt.mnt_table[0]);
    rootmnt->devno = 0;
    rootmnt->emnt = 0;
    rootmnt->refcnt = 1;
    global_mnt.rootmnt = rootmnt;
    global_mnt.mntlist = rootmnt;

    initlock(&global_mnt.lock, "gmnt");
}

struct mnt *mntalloc(){
    acquire(&global_mnt.lock);
    struct mnt *newmnt = 0;
    for(int i = 0; i < NMNT; i++){
        if(global_mnt.mnt_table[i].refcnt == 0){
            newmnt = &global_mnt.mnt_table[i];
            break;
        }
    }
    newmnt->refcnt = 2;
    release(&global_mnt.lock);
    return newmnt;
}

void mntdup(struct mnt* mntent){
    acquire(&global_mnt.lock);
    mntent->refcnt++;
    release(&global_mnt.lock);
}

void mntput(struct mnt* mntent){
    acquire(&global_mnt.lock);
    mntent->refcnt--;
    release(&global_mnt.lock);
}

