int user_stack_push_str(pagetable_t pt, uint64_t *ustack, char *str, uint64_t sp, uint64_t stackbase) {
    uint64_t argc = ++ustack[0];
    if (argc > MAXARG + 1) {
        return -1;
    }
    sp -= strlen(str) + 1;
    sp -= sp % 16; // riscv sp must be 16-byte aligned
    if (sp < stackbase) {
        return -1;
    }
    if (copyout(pt, sp, str, strlen(str) + 1) < 0) {
        printf("copyout failed\n");
        return -1;
    }
    ustack[argc] = sp;
    ustack[argc + 1] = 0;
    return sp;
}

