	disk.desc[i].next = 0;
	disk.free[i] = 1;
	if (disk.nwait > 0)
		wakeup(&disk.free[0]);
  */
}

// free a chain of descriptors.
static void free_chain(int i) {
  while(1){
    free_desc(i);
    if(disk.desc[i].flags & VRING_DESC_F_NEXT)
      i = disk.desc[i].next;
    else
      break;
  }
}

static int alloc3_desc(int *idx) {
  for(int i = 0; i < 3; i++){
    idx[i] = alloc_desc();
    if(idx[i] < 0){
      for(int j = 0; j < i; j++)
        free_desc(idx[j]);
      return -1;
    }
  }
  return 0;
}

static int alloc_descs(int * restrict idx, int n) {
	for (int i = 0; i < n; i++) {
		idx[i] = alloc_desc();
		if (idx[i] < 0) {
			for (int j = 0; j < i; j++)
				free_desc(idx[j]);
			return -1;
		}
	}
	return 0;
}

