#define Uart_reg(reg) ((volatile uint8_t *)(Uart0 + reg))

#define RHR 0 // receive
#define THR 0 // transmit
#define DLL 0 // 波特率
#define DLM 1 // 波特率
#define IER 1 // 中断
#define FCR 2 // FIFO
#define ISR 2 
#define LCR 3 // DLAB, MODE
#define MCR 4
#define LSR 5
#define MSR 6
#define SPR 7

#define LSR_RX_READY (1 << 0)
#define LSR_TX_IDLE (1 << 5)

#define uart_read_reg(reg) (*(Uart_reg(reg)))
#define uart_write_reg(reg, value) (*(Uart_reg(reg)) = (value))

struct spinlock uart_tx_lock;
#define UART_TX_BUF_SIZE 32
char uart_tx_buf[UART_TX_BUF_SIZE];
uint64_t uart_tx_w;
uint64_t uart_tx_r;
int uart_init() {

    uart_write_reg(IER, 0X00);  // 关中断

    uint8_t lcr = uart_read_reg(LCR);

    uart_write_reg(LCR, lcr | (1 << 7));

    uart_write_reg(DLL, 0x03);

    uart_write_reg(DLM, 0x00); // 设置波特率

    lcr = 0;
    uart_write_reg(LCR, lcr | (3 << 0)); //设置字长

    uart_write_reg(FCR, (1 << 0) | (3 << 1));

    uart_write_reg(IER, (1 << 0) | (1 << 1));

    initlock(&uart_tx_lock, "uart");

    return 0;
}

int uart_putc(char ch) {
    acquire(&uart_tx_lock);
    while(uart_tx_w == uart_tx_r + UART_TX_BUF_SIZE){
        sleep(&uart_tx_r, &uart_tx_lock);
    }
    uart_tx_buf[uart_tx_w % UART_TX_BUF_SIZE] = ch;
    uart_tx_w += 1;
    uart_start();
    release(&uart_tx_lock);
    return 1;
}

void uartputc_sync(int c) {
    push_off();
    while((uart_read_reg(LSR) & LSR_TX_IDLE) == 0)
      ;
    uart_write_reg(THR, c);
    pop_off();
}

void uart_start() {
    while (1) {
        if(uart_tx_w == uart_tx_r){
            return;
        }
        if((uart_read_reg(LSR) & LSR_TX_IDLE) == 0){
            return;
        }
        int c = uart_tx_buf[uart_tx_r % UART_TX_BUF_SIZE];
        uart_tx_r += 1;
        wakeup(&uart_tx_r);
        *(volatile uint8_t *)(Uart0 + THR) = c;
    }
}

void uart_puts(char * s) {
    while(*s){
        while((uart_read_reg(LSR) & LSR_TX_IDLE) == 0);
        *(volatile uint8_t *)(Uart0 + THR) = *s;
        s++;
    }
}

int uart_getc(void) {
    if(uart_read_reg(LSR) & 0x01){
        return uart_read_reg(RHR);
    } else {
        return -1;
    }
}

void uart_intr() {
    while(1){
        int c = uart_getc();
        if(c == -1)
            break;
        consoleintr(c);
    }
    acquire(&uart_tx_lock);
    uart_start();
    release(&uart_tx_lock);
}

