/* flags数组每个元素为64bit，可以表示的flag数量为：数组大小*64 */
#define BITS_PER_LONG 64
/* nr位于的，flags数组的元素下标 */
#define BIT_WORD(nr) ((nr) / BITS_PER_LONG)
/* 那个元素的哪一位 */
#define BIT_MASK(nr) (1UL << ((nr) % BITS_PER_LONG))

static inline int test_bit(unsigned int nr, const volatile uint64_t *addr) {
  return 1UL & (addr[BIT_WORD(nr)] >> (nr & (BITS_PER_LONG - 1)));
}

static inline void clear_bit(unsigned int nr, uint64_t *addr) {
  // printf("%p", addr[BIT_WORD(nr)]);
  addr[BIT_WORD(nr)] &= (0xffffffff ^ (1 << nr));
  // printf("%p", addr[BIT_WORD(nr)]);
}

