#define CLK_FREQ     10000000
static inline uint64_t convert_from_timespec2(const struct timespec2 *ts)
{
	uint64_t time = ts->tv_sec * CLK_FREQ + ts->tv_nsec * (CLK_FREQ / 1000 / 100) / 10 / 1000;
	return time;
}

