struct {
    struct spinlock lock;
    struct file file[NFILE];
} ftable;

void fileinit(void){
    initlock(&ftable.lock, "ftable");
    struct file *f;
    for(f = ftable.file; f < ftable.file + NFILE; f++){
        memset(f, 0, sizeof(struct file));
    }
}

struct file * filealloc(void){
    struct file *f;

    acquire(&ftable.lock);
    for(f = ftable.file; f < ftable.file + NFILE; f++){
        if(f->ref == 0){
            f->ref = 1;
            release(&ftable.lock);
            return f;
        }
    }
    release(&ftable.lock);
    return 0;
}

struct file* filedup(struct file *f){
    acquire(&ftable.lock);
    if(f->ref < 1){
        panic("filedup");
    }
    f->ref ++;
    release(&ftable.lock);
    return f;
}

void fileclose(struct file* f){
    struct file f1;

    acquire(&ftable.lock);
    if(f->ref < 1){
        panic("fileclose");
    }
    if(--f->ref > 0){
        release(&ftable.lock);
        return ;
    }

    f1 = *f;
    f->ref = 0;
    f->type = FD_NONE;
    release(&ftable.lock);

    if(f1.type == FD_PIPE){
        pipeclose(f1.pipe, f1.writable);
    } else if(f1.type == FD_INODE || f1.type == FD_DEVICE){
        iput(f1.ip);
    }
}

int filestat(struct file *f, uint64_t addr){
    struct proc *p = myproc();
    struct stat st;

    if(f->type == FD_INODE || f->type == FD_DEVICE){
        ilock(f->ip);
        stati(f->ip, &st);
        iunlock(f->ip);
        if(copyout(p->pagetable, addr, (char *)&st, sizeof(st)) < 0){
            return -1;
        }
        return 0;
    }
    return -1;
}

