struct buf* bread(uint32_t dev, uint32_t sect){
    struct buf *b;

    b = bget(dev, sect);
    if(! b->valid){
        virtio_disk_rw(b, 0);
        b->valid = 1;
    }
    return b;
}

// write the disk from the buffer in mem to disk
void bwrite(struct buf *b){
    /*
    if(!holdingsleep(&b->lock)){
