    }
    */
    virtio_disk_rw(b, 1);
}

void brelse(struct buf *b){
    if(!holdingsleep(&b->lock)){
        panic("brelse");
    }
    releasesleep(&b->lock);

    acquire(&bcache.lock);

    b->refcnt --;

    /* LRU : if the buffer's refcnt equal zero, put it behind head*/
    if(b->refcnt == 0){
        b->next->prev = b->prev;
        b->prev->next = b->next;
        //printf("brelse start: %x\n", b);
        b->next = bcache.head.next;
        b->prev = &bcache.head;
        bcache.head.next->prev = b;
        bcache.head.next = b;
    }

    release(&bcache.lock);
}

void bpin(struct buf *b) {
    acquire(&bcache.lock);
    b->refcnt++;
    release(&bcache.lock);
}

void bunpin(struct buf *b) {
    acquire(&bcache.lock);
    b->refcnt--;
    release(&bcache.lock);
}

/*  
 * This code segment implements a simple console interface for a RISC-V based operating system.  
 * It provides functionalities for reading from and writing to the console, handling character input,  
 * and echoing characters to the UART (Universal Asynchronous Receiver/Transmitter) interface.  
 *   
 * The `consputc` function echoes a character to the UART interface, handling backspace characters specially.  
 * The `consolewrite` function writes data from user space to the console, copying characters from user space to kernel space and echoing them.  
 * The `consoleread` function reads data from the console buffer into user space, handling special control characters and waking up processes waiting for input.  
 * The `consoleintr` function is called when a character is received by the UART, adding it to the console input buffer and potentially waking up waiting processes.  
 * Lastly, `consoleinit` initializes the console, setting up the necessary locks and UART interface, and registering the console read and write functions with the device switch.  
 */  

#include <stdarg.h>
#include "types.h"
#include "spinlock.h"
#include "sleeplock.h"
#include "fs.h"
#include "file.h"
#include "memlayout.h"
